"use client";

import React, { useState } from "react";
import { UploadZone } from "@/components/UploadZone";
import { RiskMeter } from "@/components/RiskMeter";
import { RoadmapTimeline } from "@/components/RoadmapTimeline";
import { Skeleton } from "@/components/ui/skeleton";
import { Button } from "@/components/ui/button";
import { motion, AnimatePresence } from "framer-motion";
import { Download, Printer } from "lucide-react";

export default function DashboardPage() {
    const [isProcessing, setIsProcessing] = useState(false);
    const [analysisComplete, setAnalysisComplete] = useState(false);
    const [analysisData, setAnalysisData] = useState<unknown>(null);

    const handleUpload = async (file: File) => {
        setIsProcessing(true);
        try {
            const formData = new FormData();
            formData.append("file", file);

            const response = await fetch("/api/analyze-contract", {
                method: "POST",
                body: formData,
            });

            if (!response.ok) {
                throw new Error("Failed to analyze contract");
            }

            const data = await response.json();
            setAnalysisData(data.analysis || data);
            setAnalysisComplete(true);
        } catch (error: unknown) {
            console.error("Upload error:", error);
            alert(error instanceof Error ? error.message : "An error occurred while analyzing the document.");
        } finally {
            setIsProcessing(false);
        }
    };

    const handleExportJSON = () => {
        if (!analysisData) return;
        const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(analysisData, null, 2));
        const downloadAnchorNode = document.createElement("a");
        downloadAnchorNode.setAttribute("href", dataStr);
        downloadAnchorNode.setAttribute("download", "scope_shield_analysis.json");
        document.body.appendChild(downloadAnchorNode); // required for firefox
        downloadAnchorNode.click();
        downloadAnchorNode.remove();
    };

    const handleExportCSV = () => {
        if (!(analysisData as { tasks?: any[] })?.tasks) return;
        const tasks = (analysisData as { tasks: any[] }).tasks;
        const csvRows = [];

        // Headers
        csvRows.push(["ID", "Title", "Type", "Status", "Description"].join(","));

        // Rows
        for (const task of tasks) {
            const row = [
                task.id,
                `"${task.title.replace(/"/g, '""')}"`,
                task.type,
                task.status,
                `"${task.description.replace(/"/g, '""')}"`
            ];
            csvRows.push(row.join(","));
        }

        const csvString = csvRows.join("\n");
        const dataStr = "data:text/csv;charset=utf-8," + encodeURIComponent(csvString);
        const downloadAnchorNode = document.createElement("a");
        downloadAnchorNode.setAttribute("href", dataStr);
        downloadAnchorNode.setAttribute("download", "scope_shield_tasks.csv");
        document.body.appendChild(downloadAnchorNode);
        downloadAnchorNode.click();
        downloadAnchorNode.remove();
    };

    return (
        <div className="space-y-8 pb-12">
            {!analysisComplete ? (
                <div className="relative">
                    <AnimatePresence mode="popLayout">
                        {isProcessing ? (
                            <motion.div
                                key="loading-skeleton"
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, scale: 0.95 }}
                                className="space-y-8 w-full"
                            >
                                <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                                    <div className="space-y-2">
                                        <Skeleton className="h-8 w-48" />
                                        <Skeleton className="h-4 w-64" />
                                    </div>
                                    <div className="flex items-center gap-4">
                                        <Skeleton className="h-14 w-32 rounded-xl" />
                                        <Skeleton className="h-10 w-40 rounded-lg" />
                                    </div>
                                </div>
                                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                                    <div className="lg:col-span-1 border border-slate-200 dark:border-slate-800 rounded-2xl p-6 h-full flex flex-col justify-between">
                                        <Skeleton className="h-6 w-3/4 mx-auto mb-6" />
                                        <div className="flex justify-center flex-1 items-center">
                                            <Skeleton className="h-32 w-32 rounded-full" />
                                        </div>
                                        <Skeleton className="h-10 w-full rounded-full mt-6" />
                                    </div>
                                    <div className="lg:col-span-2 border border-slate-200 dark:border-slate-800 rounded-2xl p-8 space-y-8">
                                        <div className="flex justify-between">
                                            <Skeleton className="h-6 w-1/3" />
                                            <Skeleton className="h-6 w-24 rounded-full" />
                                        </div>
                                        <div className="space-y-6">
                                            {[1, 2, 3].map((i) => (
                                                <div key={i} className="flex gap-4">
                                                    <Skeleton className="h-12 w-12 rounded-full shrink-0" />
                                                    <div className="space-y-2 flex-1">
                                                        <Skeleton className="h-5 w-1/2" />
                                                        <Skeleton className="h-4 w-full" />
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                            </motion.div>
                        ) : (
                            <motion.div
                                key="uploading"
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, y: -20 }}
                                className="flex flex-col items-center justify-center py-12"
                            >
                                <div className="text-center mb-8 max-w-xl">
                                    <h2 className="text-3xl font-bold mb-4">Analyze a New Contract</h2>
                                    <p className="text-slate-600 dark:text-slate-400">
                                        Upload your freelance agreement, statement of work, or contract. We&apos;ll automatically identify deliverables, payment milestones, and flag potential scope creep risks.
                                    </p>
                                </div>
                                <UploadZone onUpload={handleUpload} isProcessing={isProcessing} />
                            </motion.div>
                        )}
                    </AnimatePresence>
                </div>
            ) : (
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    className="space-y-8"
                >
                    <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                        <div>
                            <h2 className="text-2xl font-bold">Analysis Results</h2>
                            <p className="text-slate-500">Website_Redesign_Agreement_v2.pdf</p>
                        </div>

                        <div className="flex flex-col sm:flex-row items-end sm:items-center gap-4">
                            <div className="flex items-center gap-2 mr-2">
                                <Button variant="outline" size="sm" onClick={handleExportCSV} className="gap-2">
                                    <Download className="h-4 w-4" /> CSV
                                </Button>
                                <Button variant="outline" size="sm" onClick={handleExportJSON} className="gap-2">
                                    <Download className="h-4 w-4" /> JSON
                                </Button>
                                <Button variant="outline" size="sm" onClick={() => window.print()} className="gap-2">
                                    <Printer className="h-4 w-4" /> Print
                                </Button>
                            </div>

                            <div className="flex flex-col items-end px-4 py-2 bg-emerald-50 border border-emerald-100 dark:bg-emerald-900/20 dark:border-emerald-900/50 rounded-xl">
                                <span className="text-xs font-semibold uppercase tracking-wider text-emerald-600 dark:text-emerald-400">Value Protected</span>
                                <span className="text-xl font-bold text-emerald-700 dark:text-emerald-500">
                                    ${(((analysisData as { tasks?: unknown[] })?.tasks?.length || 0) * 1500).toLocaleString()}
                                </span>
                            </div>
                            <Button
                                variant="default"
                                onClick={() => setAnalysisComplete(false)}
                            >
                                Analyze Another PDF
                            </Button>
                        </div>
                    </div>

                    {/* This is where the RiskMeter and Timeline will go */}
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                        <div className="lg:col-span-1">
                            <RiskMeter score={(analysisData as { riskScore?: number })?.riskScore || 0} alerts={(analysisData as { alerts?: any[] })?.alerts || []} />
                        </div>
                        <div className="lg:col-span-2">
                            <RoadmapTimeline items={(analysisData as { tasks?: any[] })?.tasks || []} />
                        </div>
                    </div>
                </motion.div>
            )}
        </div>
    );
}
